import{f as n,D as A,o as r,c as C,a2 as a,b as d,w as o,a as l,G as s,a5 as i}from"./chunks/framework.Ccw_j35p.js";const B=JSON.parse('{"title":"分布式理论总览","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/distributed-theory/index.md","filePath":"high-concurrency/distributed-theory/index.md","lastUpdated":1780917900000}'),E={name:"high-concurrency/distributed-theory/index.md"};function u(g,t,h,c,p,P){const e=A("Mermaid");return r(),C("div",null,[t[2]||(t[2]=a('<h1 id="分布式理论总览" tabindex="-1">分布式理论总览 <a class="header-anchor" href="#分布式理论总览" aria-label="Permalink to &quot;分布式理论总览&quot;">​</a></h1><p>创建日期：2026-06-06</p><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>分布式理论是理解高并发架构的<strong>底层基石</strong>。没有扎实的分布式理论基础，设计出来的高并发系统就是空中楼阁。本模块从 CAP 定理出发，逐步深入到一致性协议、分布式事务、分布式 ID 和分布式锁，构建完整的分布式知识体系。</p><div class="tip custom-block"><p class="custom-block-title">为什么分布式理论对高并发如此重要？</p><p>高并发系统天然是分布式的——多实例、多机房、多数据中心。分布式环境下，网络分区、节点故障、时钟不同步是常态。不理解 CAP、一致性协议、分布式事务，你就无法在面试中回答&quot;这个设计为什么这么选&quot;。</p></div><h2 id="知识全景图" tabindex="-1">知识全景图 <a class="header-anchor" href="#知识全景图" aria-label="Permalink to &quot;知识全景图&quot;">​</a></h2>',6)),(r(),d(i,null,{default:o(()=>[s(e,{id:"mermaid-20",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20CAP%5BCAP%20%E5%AE%9A%E7%90%86%3Cbr%2F%3E%E5%88%86%E5%B8%83%E5%BC%8F%E7%90%86%E8%AE%BA%E5%9F%BA%E7%9F%B3%5D%20--%3E%20BASE%5BBASE%20%E7%90%86%E8%AE%BA%3Cbr%2F%3EAP%20%E7%B3%BB%E7%BB%9F%E7%9A%84%E8%AE%BE%E8%AE%A1%E5%93%B2%E5%AD%A6%5D%0A%20%20%20%20CAP%20--%3E%20CONSENSUS%5B%E4%B8%80%E8%87%B4%E6%80%A7%E5%8D%8F%E8%AE%AE%3Cbr%2F%3E2PC%20%2F%203PC%20%2F%20Paxos%20%2F%20Raft%5D%0A%0A%20%20%20%20CONSENSUS%20--%3E%20TRANSACTION%5B%E5%88%86%E5%B8%83%E5%BC%8F%E4%BA%8B%E5%8A%A1%3Cbr%2F%3ETCC%20%2F%20Saga%20%2F%20AT%20%E6%A8%A1%E5%BC%8F%5D%0A%20%20%20%20CONSENSUS%20--%3E%20ID%5B%E5%88%86%E5%B8%83%E5%BC%8F%20ID%3Cbr%2F%3E%E9%9B%AA%E8%8A%B1%E7%AE%97%E6%B3%95%20%2F%20Leaf%20%E5%8F%B7%E6%AE%B5%5D%0A%20%20%20%20CONSENSUS%20--%3E%20LOCK%5B%E5%88%86%E5%B8%83%E5%BC%8F%E9%94%81%3Cbr%2F%3ERedis%20%2F%20ZK%20%2F%20Etcd%5D%0A%0A%20%20%20%20style%20CAP%20fill%3A%23e3f2fd%2Cstroke%3A%232196f3%0A%20%20%20%20style%20CONSENSUS%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20TRANSACTION%20fill%3A%23fff3e0%2Cstroke%3A%23ff9800%0A%20%20%20%20style%20ID%20fill%3A%23fce4ec%2Cstroke%3A%23e91e63%0A%20%20%20%20style%20LOCK%20fill%3A%23f3e5f5%2Cstroke%3A%239c27b0%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=a('<h2 id="各模块核心问题" tabindex="-1">各模块核心问题 <a class="header-anchor" href="#各模块核心问题" aria-label="Permalink to &quot;各模块核心问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>解决什么问题</th><th>为什么必考</th><th>面试深度</th></tr></thead><tbody><tr><td><strong>CAP/BASE</strong></td><td>分布式系统不可能同时满足 C、A、P，如何取舍？</td><td>分布式设计第一问，决定架构方向</td><td>能讲清楚 PACELC 才算过关</td></tr><tr><td><strong>一致性协议</strong></td><td>多个节点如何就某个值达成一致？</td><td>理解 ZK/Raft/Etcd 的底层原理</td><td>能画出 Raft 选举流程</td></tr><tr><td><strong>分布式事务</strong></td><td>跨多个服务/数据库的事务如何保证一致性？</td><td>微服务架构的核心难题</td><td>能对比 TCC/Saga/AT 选型</td></tr><tr><td><strong>分布式 ID</strong></td><td>分布式环境下如何生成全局唯一 ID？</td><td>几乎每个系统都要用</td><td>能讲清楚雪花算法 64bit 拆解</td></tr><tr><td><strong>分布式锁</strong></td><td>多个进程/线程如何安全地竞争共享资源？</td><td>秒杀/库存扣减等场景必用</td><td>能从 SETNX 演进到 RedLock</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2>',3)),(r(),d(i,null,{default:o(()=>[s(e,{id:"mermaid-117",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5BCAP%20%E5%AE%9A%E7%90%86%5D%20--%3E%20B%5B%E4%B8%80%E8%87%B4%E6%80%A7%E5%8D%8F%E8%AE%AE%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%88%86%E5%B8%83%E5%BC%8F%E4%BA%8B%E5%8A%A1%5D%0A%20%20%20%20B%20--%3E%20D%5B%E5%88%86%E5%B8%83%E5%BC%8F%20ID%5D%0A%20%20%20%20B%20--%3E%20E%5B%E5%88%86%E5%B8%83%E5%BC%8F%E9%94%81%5D%0A%0A%20%20%20%20style%20A%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20B%20fill%3A%23e3f2fd%2Cstroke%3A%232196f3%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[l(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=a('<ol><li><strong>先理解 CAP</strong>：这是所有分布式理论的基石，理解为什么 CAP 不能同时满足。</li><li><strong>再学一致性协议</strong>：理解了 2PC/3PC/Paxos/Raft，就理解了达成一致的底层机制。</li><li><strong>然后分三路</strong>：分布式事务（一致性协议的应用）、分布式 ID（全局唯一性）、分布式锁（互斥性）。</li><li><strong>画图总结</strong>：每个协议的状态流转画出来，面试时才能清晰表达。</li></ol><h2 id="面试考察重点" tabindex="-1">面试考察重点 <a class="header-anchor" href="#面试考察重点" aria-label="Permalink to &quot;面试考察重点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">高频考点</p><ol><li><strong>CAP 为什么不能同时满足？</strong> 画出网络分区场景下的取舍逻辑。</li><li><strong>Raft 选举过程</strong>：Term、RequestVote、心跳机制，能画序列图。</li><li><strong>TCC 空回滚和悬挂</strong>：这两个问题怎么产生的？怎么解决？</li><li><strong>雪花算法 64bit 拆解</strong>：41 位时间戳 + 10 位机器 ID + 12 位序列号，时钟回拨怎么办？</li><li><strong>RedLock 争议</strong>：Martin Kleppmann 的核心论点是什么？实际项目中怎么用？</li></ol></div><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>混淆 CAP 和 ACID，CAP 是分布式系统的，ACID 是单机数据库的。</li><li>把 Paxos 和 Raft 当成一回事，说不清区别。</li><li>只知道 TCC 三个字母，讲不清楚 Try/Confirm/Cancel 具体做了什么。</li><li>分布式锁只说 SETNX，不知道看门狗、RedLock。</li><li>雪花算法说不清 64 位怎么分配的，时钟回拨没方案。</li></ul></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>《Designing Data-Intensive Applications》（DDIA）—— Martin Kleppmann</li><li>《Paxos Made Simple》—— Leslie Lamport</li><li><a href="https://raft.github.io/" target="_blank" rel="noreferrer">Raft 可视化动画</a></li><li><a href="https://seata.io/" target="_blank" rel="noreferrer">Seata 官方文档</a></li><li><a href="https://github.com/redisson/redisson/wiki" target="_blank" rel="noreferrer">Redisson 分布式锁文档</a></li></ul><hr><h2 id="经典高频面试题" tabindex="-1">经典高频面试题 <a class="header-anchor" href="#经典高频面试题" aria-label="Permalink to &quot;经典高频面试题&quot;">​</a></h2><h3 id="q1-cap-为什么不能同时满足-画图说明。" tabindex="-1">Q1：CAP 为什么不能同时满足？画图说明。 <a class="header-anchor" href="#q1-cap-为什么不能同时满足-画图说明。" aria-label="Permalink to &quot;Q1：CAP 为什么不能同时满足？画图说明。&quot;">​</a></h3><p><strong>面试回答策略：</strong> 先亮出核心结论（P 发生时 C 和 A 只能二选一），然后画一个网络分区的图（两个机房之间画一个 X 表示断连），用你自己的真实项目举例说明 &quot;我们当时在什么时候遇到了这个取舍&quot;。最后给出你们的选择和理由。面试官不看图多漂亮，看的是你在真实压力下怎么做决策。</p><p><strong>我们当时的跨机房积分系统</strong>就是最好的回答素材。把代码拿到面试官面前：&quot;我们北京和上海两个机房的积分 Redis，专线被挖断了（P 发生）。北京的用户消费积分减了、上海的用户查积分还是老的——超用了 327 个用户 1.2 万积分。这就是选了 A 的代价。但我们没有选 C——因为如果选 C 意味着网络分区时所有读请求返回错误，用户直接不能下单，影响是数万元的 GMV 损失。这个权衡是经过业务方确认的。&quot;</p><p><strong>关键表达：</strong></p><ul><li>不要说 &quot;CAP 理论说不能同时满足&quot;——面试官知道你背了书。</li><li>要说 &quot;我们当时在 XX 场景遇到了网络分区，我们的选择是 YY，因为 ZZ。结果是 AA，教训是 BB。&quot;</li><li>用量化数字：超用 327 人 / 1200 元 vs 选 C 的 GMV 损失数万元。</li><li>用决策理由：为什么这个业务选 AP 而不是 CP。</li></ul><p><strong>常见追问准备：</strong></p><ul><li><strong>追问 1：</strong> &quot;如果让你们重来一次，还会选 AP 吗？&quot; → 答：会。但会加上&quot;分区期间冻结跨机房操作&quot;的前置判断逻辑。被动恢复不如主动预防。</li><li><strong>追问 2：</strong> &quot;那是什么场景下你会选 CP？&quot; → 答：涉及资金的支付系统。宁可 5 秒不可用，不能一笔钱被转两次。</li><li><strong>追问 3：</strong> &quot;这和你用的框架（Redis/ZK/Nacos）的选型有什么关系？&quot; → 答：直接关系。积分系统用了 Redis Cluster（AP 系统），因为积分的 CAP 选择是 AP。支付系统用了 ZK（CP 系统），因为支付的 CAP 选择是 CP。CAP 不是抽象概念——它直接决定了你的技术选型。</li></ul><h3 id="q2-base-理论的核心思想是什么-和-acid-有什么区别" tabindex="-1">Q2：BASE 理论的核心思想是什么？和 ACID 有什么区别？ <a class="header-anchor" href="#q2-base-理论的核心思想是什么-和-acid-有什么区别" aria-label="Permalink to &quot;Q2：BASE 理论的核心思想是什么？和 ACID 有什么区别？&quot;">​</a></h3><p><strong>面试回答策略：</strong> 不说废话，举真实的例子。我们电商系统中：BASE 和 ACID 在同一个订单流程里同时存在，BASE 在最终端，ACID 在核心点。</p><p>举我们的流程：用户下单 → 本地 ACID 写订单（强一致）→ 通过 RocketMQ 异步通知履约系统（BASE，最终一致）→ 履约系统拣货 → 最终一致。</p><p>为什么这么设计：</p><ul><li>下单是核心操作，必须 ACID 强一致——订单不存在就不能往下走。</li><li>通知履约系统不需要强一致——用户下单后 1 分钟内拣货都算正常，最终能通知到就行，允许延迟。所以用 BASE。</li></ul><p><strong>关键区别总结：</strong></p><table tabindex="0"><thead><tr><th>对比维度</th><th>ACID</th><th>BASE</th></tr></thead><tbody><tr><td>范围</td><td>单机数据库事务</td><td>分布式系统</td></tr><tr><td>一致性</td><td>强一致</td><td>最终一致</td></tr><tr><td>可用性</td><td>差（有锁）</td><td>高（异步）</td></tr><tr><td>适用场景</td><td>核心操作（写订单、扣余额）</td><td>非核心、异步操作（通知、同步）</td></tr></tbody></table><p><strong>真实案例：我们日订单 12 万单，通知履约系统的延迟要求是 99.9% 在 30 秒内完成，我们用 BASE（本地消息表 + RocketMQ）刚好满足这个要求，同时让下单接口的 RT 从 200ms 降到了 80ms——这就是 BASE 换性能的价值。</strong></p><p><strong>常见追问准备：</strong></p><ul><li><strong>追问 1：</strong> &quot;BASE 不要求强一致，那什么时候会最终一致？&quot; → 答：我们的 SLA 是 5 分钟内 99.99% 一致。5 分钟超过就是故障触发报警。不能把&quot;最终&quot;理解为&quot;不管什么时候都行&quot;——必须有量化的最终一致性 SLA。</li><li><strong>追问 2：</strong> &quot;ACID 和 BASE 一定是二选一吗？&quot; → 答：不是。同一个流程里可以同时存在——我刚才举的下单 + 通知就是 ACID 在本地、BASE 在跨服务之间。分布式系统中绝对的 ACID 不可能，全链路 BASE 风险又太高，所以组合使用是最常见的。</li><li><strong>追问 3：</strong> &quot;怎么评估一个业务场景适合 BASE 还是 ACID？&quot; → 答：看用户体验和资损风险：用户感知不到延迟 + 资损可以补偿 → 用 BASE。用户感知得到 + 资损不可接受 → 用 ACID。</li></ul><h3 id="q3-强一致性和最终一致性分别用在什么场景" tabindex="-1">Q3：强一致性和最终一致性分别用在什么场景？ <a class="header-anchor" href="#q3-强一致性和最终一致性分别用在什么场景" aria-label="Permalink to &quot;Q3：强一致性和最终一致性分别用在什么场景？&quot;">​</a></h3><p><strong>面试回答策略：</strong> 给出你的&quot;一致性分级&quot;——不是二选一，而是根据一致性的严格度把它分成三个等级。用你自己的项目案例把每一级说明。</p><ol><li><strong>强一致（ACID / 2PC / TCC）</strong>：资金转账、支付扣费、余额变更。一致性窗口 = 0（实时）。我们支付系统用 TCC 模式，日均 1.5 万笔支付，失败率 0.3%。代价是 TCC 的开发和维护成本高。</li><li><strong>准实时一致（读己之写 / 本地消息表 5 秒内）</strong>：订单详情、购物车。一致性窗口 &lt; 5 秒。我们下单→订单详情使用了&quot;支付成功 30 秒内走主库&quot;，剩余走从库。代价是主库增加了 15% 的读负载。</li><li><strong>最终一致（异步 MQ / 补偿扫描 1-5 分钟）</strong>：通知履约、发优惠券、推送消息、点赞数。我们订单履约的最终一致性 SLA 是 5 分钟 99.99%。代价是消息延迟从 50ms 涨到 1-2 秒，但履约时效要求是 30 分钟内，无影响。</li></ol><p><strong>量化对比：</strong></p><table tabindex="0"><thead><tr><th>一致性等级</th><th>窗口</th><th>实现方式</th><th>性能代价</th><th>我们的场景</th></tr></thead><tbody><tr><td>强一致</td><td>0</td><td>TCC / AT</td><td>RT +20-50ms</td><td>支付、余额、库存</td></tr><tr><td>准实时</td><td>&lt; 5s</td><td>走主库 / 本地消息表</td><td>DB 负载 +15%</td><td>订单详情</td></tr><tr><td>最终一致</td><td>1-5 min</td><td>RocketMQ / 补偿</td><td>消息延迟 1-2s</td><td>履约通知、推送</td></tr></tbody></table><p><strong>常见追问准备：</strong></p><ul><li><strong>追问 1：</strong> &quot;你刚说准实时一致 5 秒内，为什么是 5 秒不是 1 秒？&quot; → 答：根据主从同步的 P99 延迟来定的。我们 MySQL 主从延迟 P99 约 120ms，但极端大事务场景会到 800ms。取 5 秒是 800ms × 6 倍的保守缓冲，确保 99.99% 的请求都能读到最新数据。</li><li><strong>追问 2：</strong> &quot;最终一致性一定会最终一致吗？如果补偿一直失败怎么办？&quot; → 答：三级兜底：自动重试 3 次（间隔递增）→ 创建工单人工处理 → 财务对账脚本做增量对账（天级）。最后的对账是最终的防线，保证即使补偿逻辑出错，对账也一定能发现并修复差异。</li></ul><h3 id="q4-分布式理论的学习路径是什么" tabindex="-1">Q4：分布式理论的学习路径是什么？ <a class="header-anchor" href="#q4-分布式理论的学习路径是什么" aria-label="Permalink to &quot;Q4：分布式理论的学习路径是什么？&quot;">​</a></h3><p><strong>面试回答策略：</strong> 这个问题在考察你是否具备系统学习的方法论。不要只说&quot;先学 CAP 再学 Raft&quot;——面试官要听的是你具体怎么学的、踩了哪些坑、从哪里找到的答案。</p><p><strong>我的学习路径分三个阶段：</strong></p><p><strong>第一轮：概念理解（2 周）。</strong> 目标：能用自己的话向其他工程师解释这些概念，不用背定义。方法：读 DDIA 第 1-2、5-9 章 + 画思维导图。同时做一个练习——给你一个场景（比如&quot;订单系统如何 CAP 选型&quot;），在 10 分钟内用概念框架做出选择并写出理由。</p><p><strong>第二轮：动手验证（1 个月）。</strong> 这是最关键也是最容易被跳过的一步。我在 Docker 中搭了 Etcd 3 节点集群，手工触发 leader election 然后观察日志。在本地用 Docker Compose 搭了 Seata 环境，写了 TCC 的 Try/Confirm/Cancel 代码，手工模拟空回滚和悬挂场景。这些动手经历让我在面试中能区分&quot;书上的答案&quot;和&quot;实际发生了什么&quot;。</p><p><strong>第三轮：反思重构（持续进行）。</strong> 目标：把零散的坑和经验串成框架。我做的事是把公司过去 2 年的线上故障（CAP 相关 3 次、分布式事务 2 次、分布式锁 4 次）全部归类总结，每一个故障对应分布式理论中的一个概念。这样面试时每个理论点都有实战案例支撑。</p><p><strong>最终形成的面试框架：</strong></p><ul><li>CAP：积分系统跨机房分区 → 部分订单超用（AP 的代价）</li><li>Raft：Etcd 选举超时误判 → 调优到 1500-2000ms</li><li>TCC：第三方 WMS 的空回滚 → tcc_transaction_log 解决</li><li>雪花算法：NTP 闰秒回拨 1 秒 → 5ms 等待 + Redis 兜底</li><li>Redis 锁：SETNX 原子性 → 改为 SET NX PX</li></ul><p><strong>常见追问准备：</strong></p><ul><li><strong>追问 1：</strong> &quot;DDIA 你全部读完了吗？&quot; → 答：重点读了第 1-2 章（可靠性、数据模型）、第 5-9 章（复制、分区、事务、一致性与共识）、第 12 章（数据系统的未来）。DDIA 是分布式系统的圣经，用来建立框架非常好，但具体实现细节需要结合官方文档和源码看。</li><li><strong>追问 2：</strong> &quot;你说的动手验证部分，你有什么印象深刻的学习产出吗？&quot; → 答：Etcd 的选举调优。我在 Docker 里用 tc 命令模拟网络延迟（<code>tc qdisc add dev eth0 root netem delay 100ms</code>），测试了不同 heartbeat interval 和 election timeout 下的选举行为。做完后发现一个之前不理解的点：为什么 Raft 选举超时必须随机化——如果不随机，三个节点同时超时、同时发起选举，票数被分散导致无限循环。</li></ul><h3 id="q5-zookeeper、etcd、nacos-分别是什么-cap-类型" tabindex="-1">Q5：ZooKeeper、Etcd、Nacos 分别是什么 CAP 类型？ <a class="header-anchor" href="#q5-zookeeper、etcd、nacos-分别是什么-cap-类型" aria-label="Permalink to &quot;Q5：ZooKeeper、Etcd、Nacos 分别是什么 CAP 类型？&quot;">​</a></h3><p><strong>面试回答策略：</strong> 不要只回答类别，要给出&quot;这个系统在实际中出过什么问题让你深刻理解了它的 CAP 属性&quot;。面试官想确认你真的用过这些系统，而不是背了文档。</p><p><strong>我们公司的真实经历：</strong></p><ol><li><p><strong>ZooKeeper（CP）</strong>——我们的 ZK 集群（3 节点）经历过一次 Leader 节点 Full GC 暂停 15 秒 → ZK Session 超时 → Leader 选举 8 秒 → 数据同步 20 秒 → 总计 43 秒完全不可写。这就是 CP 的代价——Leader 选举时宁可不可用，也绝不丢失一致性。配置中心的所有改操作（服务上下线）在这 43 秒内全部被拒绝。如果是 AP 系统，这期间还能写但可能数据不一致。这就是 CP vs AP 的最直接对比。</p></li><li><p><strong>Etcd（CP）</strong>——K8s 的 Etcd 集群（3 节点），Pod 滚动更新时读请求暴增（QPS 2000→8000），一个 Follower 误判 Leader 挂了触发选举，导致 8 秒不可用。Etcd 的 Raft 选举比 ZK（ZAB）更快（平均 2-5 秒 vs 8-15 秒），越快的选举是因为 Raft 把 Leader 切换设计得更干净。这是 Raft &quot;可理解性&quot;优势的体现。</p></li><li><p><strong>Nacos（AP + CP 可切换）</strong>——服务器交换机重启导致 Nacos 3 节点网络分区 3 分钟。临时实例（服务发现）AP 模式正常工作（成功率从 99.7% 降到 98.2%），持久实例（配置中心）CP 模式正常工作（Leader 在多数派分区中）。这是&quot;分而治之&quot;的体现——Nacos 没有绕过 CAP，它是把不同数据分类做了不同选择。</p></li></ol><p><strong>量化对比：</strong></p><table tabindex="0"><thead><tr><th>系统</th><th>CAP</th><th>选举时间</th><th>我们遇到的故障</th><th>教训</th></tr></thead><tbody><tr><td>ZK</td><td>CP</td><td>8-15s</td><td>Full GC 引发 43s 不可用</td><td>ZK 不适合 Java GC 敏感的链路</td></tr><tr><td>Etcd</td><td>CP</td><td>2-5s</td><td>过高 QPS 引发误选举 8s</td><td>需为 Etcd 配置独立 SSD</td></tr><tr><td>Nacos</td><td>AP/CP</td><td>-</td><td>网络分区 3 分钟，成功率仍 98.2%</td><td>AP/CP 切换是真实可用的</td></tr><tr><td>Eureka</td><td>AP</td><td>-</td><td>3% 丢包下自我保护防止大量误踢</td><td>AP 在服务发现中才是正确选择</td></tr></tbody></table><p><strong>常见追问准备：</strong></p><ul><li><strong>追问 1：</strong> &quot;Nacos 的 AP/CP 可以随时切换吗？&quot; → 答：不是随时切换，是同一套集群里数据分类区分。临时实例（服务发现）就是 AP，持久实例（配置中心）就是 CP——这个选择是注册服务实例时指定的（<code>ephemeral=true/false</code>），不是运行中切换。运行中是固定的。</li><li><strong>追问 2：</strong> &quot;如果一个公司同时用多个 CAP 类型的注册中心（ZK、Nacos、Eureka），你怎么统一管理？&quot; → 答：我们公司确实同时用过 Eureka（历史遗留）→ Nacos（新项目）→ ZK（配置中心保留）。管理策略是各管各的，但监控统一——通过统一的注册中心健康检查脚本，轮询所有注册中心的健康状态，异常统一告警。运维成本确实高，所以我们在推动 Eureka 完全下线，统一到 Nacos。</li></ul>',50))])}const f=n(E,[["render",u]]);export{B as __pageData,f as default};
